import{_ as a,o as i,c as o,ag as r}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Normas de Tableros de Control","description":"","frontmatter":{},"headers":[],"relativePath":"es/standards/electrical/control-panels.md","filePath":"es/standards/electrical/control-panels.md"}'),s={name:"es/standards/electrical/control-panels.md"};function l(n,e,c,t,d,p){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="normas-de-tableros-de-control" tabindex="-1">Normas de Tableros de Control <a class="header-anchor" href="#normas-de-tableros-de-control" aria-label="Permalink to &quot;Normas de Tableros de Control&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>Las normas de tableros de control definen los requisitos para el diseño, construcción, cableado y protección de tableros de control industrial.</p><p>Aseguran que los tableros sean seguros, confiables y adecuados para su entorno y aplicación.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>Las normas de tableros de control se utilizan para:</p><ul><li>Garantizar la operación segura de sistemas eléctricos y de control</li><li>Definir prácticas de construcción y cableado</li><li>Establecer requisitos para la selección y protección de componentes</li><li>Apoyar procesos de inspección, aprobación y certificación</li><li>Reducir riesgos relacionados con fallas eléctricas y ensamblaje incorrecto</li></ul><p>Proporcionan un enfoque estructurado para construir tableros que cumplan con requisitos regulatorios y operativos.</p><h2 id="como-funciona" tabindex="-1">Cómo Funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo Funciona&quot;">​</a></h2><p>Estas normas definen:</p><ul><li>Requisitos del gabinete (grado de protección, espaciamiento, accesibilidad)</li><li>Prácticas de cableado (ruteo, segregación, identificación)</li><li>Dispositivos de protección (sobrecorriente, cortocircuito, medios de desconexión)</li><li>Requisitos de componentes (capacidades, certificaciones, compatibilidad)</li><li>Marcado y documentación</li></ul><p>Los tableros se diseñan y ensamblan conforme a estos requisitos, y pueden ser evaluados por un organismo de certificación dependiendo de la región.</p><p>Diferentes normas pueden enfatizar:</p><ul><li>Detalles constructivos y prácticas obligatorias</li><li>Desempeño a nivel sistema y principios de seguridad</li><li>Certificación versus autodeclaración</li></ul><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>Las normas de tableros de control aplican a:</p><ul><li>Tableros de automatización industrial</li><li>Tableros de control de motores</li><li>Sistemas de control de maquinaria</li><li>Tableros de distribución y auxiliares</li><li>Tableros de equipos OEM</li></ul><p>Son críticas en cualquier sistema donde el control y la protección eléctrica estén integrados en un mismo gabinete.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones Clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones Clave&quot;">​</a></h2><ul><li>Las normas aplicables dependen de la región donde se instalará el tablero</li><li>Las capacidades de los componentes deben ser compatibles con el diseño general del tablero</li><li>La capacidad de corriente de cortocircuito (SCCR) debe definirse correctamente</li><li>Es necesaria una adecuada segregación entre cableado de potencia y control</li><li>La certificación puede ser obligatoria para la aprobación de instalación</li></ul><h2 id="notas-practicas" tabindex="-1">Notas Prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas Prácticas&quot;">​</a></h2><ul><li>Siempre diseña los tableros conforme a los requisitos de la región de destino</li><li>No asumas que la certificación de componentes garantiza el cumplimiento del tablero completo</li><li>Verifica el SCCR desde etapas tempranas del diseño para evitar rediseños</li><li>Mantén un etiquetado y documentación claros para inspección</li><li>Un mal diseño de tablero puede provocar sobrecalentamiento, fallas o rechazo en inspecciones</li></ul>',22)])])}const b=a(s,[["render",l]]);export{m as __pageData,b as default};
